/**
 * Acceptance Tests -- pact_status (Check Request Status)
 *
 * Traces to: US-005, US-012
 *
 * Tests exercise the pact_status driving port (tool handler) against
 * real local git repos. Scenarios verify:
 *   - Returns "completed" with full response for finished requests
 *   - Returns "pending" with no response for waiting requests
 *   - Searches across all lifecycle directories
 *   - Returns clear error for non-existent request ID
 *   - Falls back to local state when git pull fails
 *   - Is a read-only operation (no commits)
 *   - Returns thread_id and attachments in request data (US-002a/003a)
 *   - Returns resolved attachment_paths when request has attachments (US-012)
 *
 * Error/edge scenarios: 4 of 11 total (36%)
 */

import { describe, it, expect, afterEach } from "vitest";
import {
  createTestRepos,
  seedPendingRequest,
  listDir,
  readRepoJSON,
  fileExists,
  gitPull,
  type TestRepoContext,
} from "./helpers/setup-test-repos";
import { given, when, thenAssert } from "./helpers/gwt";
import { writeFileSync } from "node:fs";
import { join } from "node:path";
import { execSync } from "node:child_process";

import { createPactServer } from "../../src/server.ts";

/** Seed a completed request + response. */
function seedCompletedRequest(
  repoPath: string,
  requestId: string,
  recipient: string,
  sender: string,
  responseBundle: Record<string, unknown>,
): void {
  // Write request to completed (not pending)
  const envelope = {
    request_id: requestId,
    request_type: "sanity-check",
    sender: { user_id: sender, display_name: sender.charAt(0).toUpperCase() + sender.slice(1) },
    recipient: { user_id: recipient, display_name: recipient.charAt(0).toUpperCase() + recipient.slice(1) },
    status: "pending",
    created_at: "2026-02-21T14:30:22.000Z",
    context_bundle: { question: "Test question" },
  };
  writeFileSync(
    join(repoPath, "requests", "completed", `${requestId}.json`),
    JSON.stringify(envelope, null, 2),
  );

  // Write response
  const response = {
    request_id: requestId,
    responder: { user_id: recipient, display_name: recipient.charAt(0).toUpperCase() + recipient.slice(1) },
    responded_at: "2026-02-21T16:00:00.000Z",
    response_bundle: responseBundle,
  };
  writeFileSync(
    join(repoPath, "responses", `${requestId}.json`),
    JSON.stringify(response, null, 2),
  );

  execSync(`cd "${repoPath}" && git add -A && git commit -m "seed completed ${requestId}" && git push`, {
    stdio: "pipe",
  });
}

/** Seed a pending request with optional thread_id and attachments. */
function seedPendingRequestWithExtensions(
  repoPath: string,
  requestId: string,
  recipient: string,
  sender: string,
  opts?: { threadId?: string; attachments?: Array<{ filename: string; description: string }> },
): void {
  const envelope: Record<string, unknown> = {
    request_id: requestId,
    request_type: "sanity-check",
    sender: { user_id: sender, display_name: sender.charAt(0).toUpperCase() + sender.slice(1) },
    recipient: { user_id: recipient, display_name: recipient.charAt(0).toUpperCase() + recipient.slice(1) },
    status: "pending",
    created_at: "2026-02-21T14:30:22.000Z",
    context_bundle: { question: "Test question" },
  };
  if (opts?.threadId) {
    envelope.thread_id = opts.threadId;
  }
  if (opts?.attachments?.length) {
    envelope.attachments = opts.attachments;
  }
  writeFileSync(
    join(repoPath, "requests", "pending", `${requestId}.json`),
    JSON.stringify(envelope, null, 2),
  );
  execSync(`cd "${repoPath}" && git add -A && git commit -m "seed ${requestId}" && git push`, {
    stdio: "pipe",
  });
}

describe("pact_status: check request status and response", () => {
  let ctx: TestRepoContext;

  afterEach(() => {
    ctx?.cleanup();
  });

  // =========================================================================
  // Happy Path
  // =========================================================================

  it("returns completed status with full response for a finished request", async () => {
    ctx = createTestRepos();
    const requestId = "req-20260221-143022-alice-a1b2";

    await given("Alice's request has been responded to by Bob", async () => {
      seedCompletedRequest(ctx.aliceRepo, requestId, "bob", "alice", {
        answer: "YES - same pattern as ZD-4102",
        evidence: "Compared refresh.ts with cleanup.ts",
        recommendation: "Apply finally-block cleanup",
      });
    });

    await when("Alice checks the status of her request", async () => {
      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      const status = await aliceServer.callTool("pact_do", { action: "check_status",
        request_id: requestId,
      }) as any;

      expect(status.status).toBe("completed");
      expect(status.response).toBeDefined();
      expect(status.response.responder.display_name).toBe("Bob");
      expect(status.response.responded_at).toMatch(/^\d{4}-\d{2}-\d{2}T/);
      expect(status.response.response_bundle).toMatchObject({
        answer: "YES - same pattern as ZD-4102",
        recommendation: "Apply finally-block cleanup",
      });
    });
  });

  it("returns pending status with no response for a waiting request", async () => {
    ctx = createTestRepos();
    const requestId = "req-20260221-143022-alice-a1b2";

    await given("Alice has sent a request that Bob has not yet responded to", async () => {
      seedPendingRequest(ctx.aliceRepo, requestId, "bob", "alice");
    });

    await when("Alice checks the status of her request", async () => {
      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      const status = await aliceServer.callTool("pact_do", { action: "check_status",
        request_id: requestId,
      }) as any;

      expect(status.status).toBe("pending");
      expect(status.response).toBeUndefined();
    });
  });

  it("includes the original request data in the status response", async () => {
    ctx = createTestRepos();
    const requestId = "req-20260221-143022-alice-a1b2";

    await given("a pending request exists", async () => {
      seedPendingRequest(ctx.aliceRepo, requestId, "bob", "alice");
    });

    await when("Alice checks status", async () => {
      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      const status = await aliceServer.callTool("pact_do", { action: "check_status",
        request_id: requestId,
      }) as any;

      expect(status.request).toMatchObject({
        request_id: requestId,
        request_type: "sanity-check",
        sender: { user_id: "alice" },
        recipient: { user_id: "bob" },
      });
    });
  });

  it("finds a request regardless of which lifecycle directory it is in", async () => {
    ctx = createTestRepos();
    const pendingId = "req-20260221-140000-alice-0001";
    const completedId = "req-20260221-140100-alice-0002";

    await given("one request is pending and another is completed", async () => {
      seedPendingRequest(ctx.aliceRepo, pendingId, "bob", "alice");
      seedCompletedRequest(ctx.aliceRepo, completedId, "bob", "alice", {
        answer: "Done",
      });
    });

    await when("Alice checks status of each request", async () => {
      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });

      const pendingStatus = await aliceServer.callTool("pact_do", { action: "check_status",
        request_id: pendingId,
      }) as any;
      expect(pendingStatus.status).toBe("pending");

      const completedStatus = await aliceServer.callTool("pact_do", { action: "check_status",
        request_id: completedId,
      }) as any;
      expect(completedStatus.status).toBe("completed");
      expect(completedStatus.response.response_bundle.answer).toBe("Done");
    });
  });

  // =========================================================================
  // Protocol Extensions: thread_id and attachments in status (US-002a/003a)
  // =========================================================================

  it("returns thread_id and attachments in the request data when present", async () => {
    ctx = createTestRepos();
    const requestId = "req-20260221-143022-alice-a1b2";
    const threadId = "req-20260221-100000-alice-0001";

    await given("a pending request exists with thread_id and attachments", async () => {
      seedPendingRequestWithExtensions(ctx.aliceRepo, requestId, "bob", "alice", {
        threadId,
        attachments: [
          { filename: "crash.log", description: "Application error log" },
          { filename: "config.yml", description: "Deployment configuration" },
        ],
      });
    });

    await when("Alice checks the status of her request", async () => {
      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      const status = await aliceServer.callTool("pact_do", { action: "check_status",
        request_id: requestId,
      }) as any;

      expect(status.status).toBe("pending");
      expect(status.request.thread_id).toBe(threadId);
      expect(status.request.attachments).toHaveLength(2);
      expect(status.request.attachments[0]).toEqual({
        filename: "crash.log",
        description: "Application error log",
      });
    });
  });

  // =========================================================================
  // Attachment Paths in Status (US-012 partial)
  // =========================================================================

  it("returns attachment_paths with absolute paths when request has attachments", async () => {
    ctx = createTestRepos();
    const requestId = "req-20260221-143022-alice-a1b2";

    await given("a pending request exists with attachments", async () => {
      seedPendingRequestWithExtensions(ctx.aliceRepo, requestId, "bob", "alice", {
        attachments: [
          { filename: "crash.log", description: "Error log" },
          { filename: "config.yml", description: "Deploy config" },
        ],
      });
    });

    await when("Alice checks the status of her request", async () => {
      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      const status = await aliceServer.callTool("pact_do", { action: "check_status",
        request_id: requestId,
      }) as any;

      expect(status.attachment_paths).toBeDefined();
      expect(status.attachment_paths).toHaveLength(2);
      expect(status.attachment_paths[0]).toEqual({
        filename: "crash.log",
        description: "Error log",
        path: join(ctx.aliceRepo, "attachments", requestId, "crash.log"),
      });
      expect(status.attachment_paths[1]).toEqual({
        filename: "config.yml",
        description: "Deploy config",
        path: join(ctx.aliceRepo, "attachments", requestId, "config.yml"),
      });
    });
  });

  it("omits attachment_paths when request has no attachments", async () => {
    ctx = createTestRepos();
    const requestId = "req-20260221-143022-alice-a1b2";

    await given("a pending request exists without attachments", async () => {
      seedPendingRequest(ctx.aliceRepo, requestId, "bob", "alice");
    });

    await when("Alice checks the status of her request", async () => {
      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      const status = await aliceServer.callTool("pact_do", { action: "check_status",
        request_id: requestId,
      }) as any;

      expect(status.attachment_paths).toBeUndefined();
    });
  });

  // =========================================================================
  // Cancelled Status
  // =========================================================================

  it("returns cancelled status when request is in cancelled/", async () => {
    ctx = createTestRepos();
    const requestId = "req-20260221-143022-alice-a1b2";

    await given("Alice's pending request has been cancelled", async () => {
      seedPendingRequest(ctx.aliceRepo, requestId, "bob", "alice");
      // Move request from pending/ to cancelled/ via git
      execSync(
        `cd "${ctx.aliceRepo}" && git mv requests/pending/${requestId}.json requests/cancelled/${requestId}.json && git commit -m "cancel ${requestId}" && git push`,
        { stdio: "pipe" },
      );
    });

    await when("Alice checks the status of her cancelled request", async () => {
      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      const status = await aliceServer.callTool("pact_do", { action: "check_status",
        request_id: requestId,
      }) as any;

      expect(status.status).toBe("cancelled");
      expect(status.request).toMatchObject({
        request_id: requestId,
        request_type: "sanity-check",
        sender: { user_id: "alice" },
        recipient: { user_id: "bob" },
      });
      expect(status.response).toBeUndefined();
    });
  });

  // =========================================================================
  // Error Paths
  // =========================================================================

  it("returns an error when request ID does not exist in any directory", async () => {
    ctx = createTestRepos();

    await when("Alice checks status of a non-existent request", async () => {
      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });

      await expect(
        aliceServer.callTool("pact_do", { action: "check_status",
          request_id: "req-nonexistent-0000",
        }),
      ).rejects.toThrow(/not found/i);
    });
  });

  it("falls back to local state with warning when git pull fails", async () => {
    ctx = createTestRepos();
    const requestId = "req-20260221-143022-alice-a1b2";

    await given("a completed request exists locally but remote is unreachable", async () => {
      seedCompletedRequest(ctx.aliceRepo, requestId, "bob", "alice", {
        answer: "Cached answer",
      });

      // Break the remote
      execSync(`mv "${ctx.remotePath}" "${ctx.remotePath}.broken"`, { stdio: "pipe" });
    });

    await when("Alice checks status with remote unreachable", async () => {
      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      const status = await aliceServer.callTool("pact_do", { action: "check_status",
        request_id: requestId,
      }) as any;

      expect(status.status).toBe("completed");
      expect(status.response.response_bundle.answer).toBe("Cached answer");
      expect(status.warning).toMatch(/stale|local/i);
    });

    // Restore for cleanup
    await thenAssert("(cleanup) restore remote", async () => {
      execSync(`mv "${ctx.remotePath}.broken" "${ctx.remotePath}"`, { stdio: "pipe" });
    });
  });

  it("status check is read-only -- no commits are created", async () => {
    ctx = createTestRepos();
    const requestId = "req-20260221-143022-alice-a1b2";

    await given("a pending request exists", async () => {
      seedPendingRequest(ctx.aliceRepo, requestId, "bob", "alice");
    });

    await when("Alice checks status", async () => {
      const commitsBefore = execSync(
        `cd "${ctx.aliceRepo}" && git rev-list --count HEAD`,
        { encoding: "utf-8" },
      ).trim();

      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      await aliceServer.callTool("pact_do", { action: "check_status",
        request_id: requestId,
      });

      const commitsAfter = execSync(
        `cd "${ctx.aliceRepo}" && git rev-list --count HEAD`,
        { encoding: "utf-8" },
      ).trim();

      // Pull may update commit count, but Alice should not have authored new commits
      // The commit count after should be the same since pull from same remote won't add commits
      // (alice already has the latest). The key check: no new commits by Alice after the call.
      const aliceCommitsAfter = execSync(
        `cd "${ctx.aliceRepo}" && git log --author="alice" --oneline | wc -l`,
        { encoding: "utf-8" },
      ).trim();
      // Alice authored seed commits but status should not add any new ones
      // We just verify the count didn't change
      expect(Number(commitsAfter)).toBe(Number(commitsBefore));
    });
  });

  it("works from any session -- not tied to the session that created the request", async () => {
    ctx = createTestRepos();
    const requestId = "req-20260221-143022-alice-a1b2";

    await given("Alice sent a request from 'Session A' (simulated by first server instance)", async () => {
      seedPendingRequest(ctx.aliceRepo, requestId, "bob", "alice");
    });

    await when("Alice checks status from 'Session B' (new server instance)", async () => {
      // The key point: a fresh server instance can find the request
      const aliceSessionB = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      const status = await aliceSessionB.callTool("pact_do", { action: "check_status",
        request_id: requestId,
      }) as any;

      expect(status.status).toBe("pending");
      expect(status.request.request_id).toBe(requestId);
    });
  });
});

tests/acceptance/inbox-enrichment.test.t.source:
/**
 * Acceptance Tests -- Inbox Pact Enrichment
 *
 * Traces to: US-020
 *
 * Tests exercise the pact_inbox driving port (tool handler) against
 * real local git repos to verify pact enrichment of inbox entries.
 * Scenarios verify:
 *   - Inbox entries include pact_description extracted from pact metadata
 *   - Inbox entries include response_fields listing expected response field names
 *   - Enrichment prefers schema.json when available for response_fields
 *   - Enrichment falls back to PACT.md when no schema.json exists
 *   - Missing or unreadable pact files cause enrichment fields to be omitted (not error)
 *   - Existing inbox fields remain unchanged after enrichment
 *   - Pact metadata is cached per request_type during a single inbox scan
 *   - Thread groups include enrichment from the latest entry's pact
 *
 * Error/edge scenarios: 4 of 9 total (44%)
 */

import { describe, it, expect, afterEach } from "vitest";
import {
  createTestRepos,
  type TestRepoContext,
} from "./helpers/setup-test-repos";
import { given, when, thenAssert } from "./helpers/gwt";
import { mkdirSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { execSync } from "node:child_process";
import { createPactServer } from "../../src/server.ts";

// ---------------------------------------------------------------------------
// Pact content fixtures
// ---------------------------------------------------------------------------

const ASK_PACT = `# Ask

A general question needing another person's view.

## When To Use
When you have a question that needs human judgment.

## Context Bundle Fields
| Field | Required | Description |
|-------|----------|-------------|
| question | yes | The question to ask |
| background | no | Background context |

## Response Structure
| Field | Description |
|-------|-------------|
| answer | The answer to the question |
| reasoning | Reasoning behind the answer |
| caveats | Any caveats or limitations |
`;

const SANITY_CHECK_SCHEMA = {
  $schema: "https://json-schema.org/draft/2020-12/schema",
  pact_name: "sanity-check",
  pact_version: "1.0.0",
  context_bundle: {
    type: "object",
    required: ["customer", "product", "issue_summary", "involved_files", "investigation_so_far", "question"],
    properties: {
      customer: { type: "string", description: "Customer name" },
      product: { type: "string", description: "Product name and version" },
      issue_summary: { type: "string", description: "Brief description" },
      involved_files: { type: "string", description: "Files examined" },
      investigation_so_far: { type: "string", description: "What you found" },
      question: { type: "string", description: "Question for reviewer" },
    },
    additionalProperties: true,
  },
  response_bundle: {
    type: "object",
    required: ["answer", "evidence", "recommendation"],
    properties: {
      answer: { type: "string", description: "YES / NO / PARTIALLY" },
      evidence: { type: "string", description: "What you compared" },
      concerns: { type: "string", description: "Risks or caveats" },
      recommendation: { type: "string", description: "Suggested next step" },
    },
    additionalProperties: true,
  },
};

/** Seed a pending request directly into the repo. */
function seedRequest(
  repoPath: string,
  opts: {
    requestId: string;
    recipient: string;
    sender: string;
    senderName: string;
    requestType?: string;
    createdAt?: string;
    question?: string;
    threadId?: string;
  },
): void {
  const envelope: Record<string, unknown> = {
    request_id: opts.requestId,
    request_type: opts.requestType ?? "sanity-check",
    sender: { user_id: opts.sender, display_name: opts.senderName },
    recipient: {
      user_id: opts.recipient,
      display_name: opts.recipient.charAt(0).toUpperCase() + opts.recipient.slice(1),
    },
    status: "pending",
    created_at: opts.createdAt ?? new Date().toISOString(),
    context_bundle: { question: opts.question ?? "Test question" },
  };
  if (opts.threadId) {
    envelope.thread_id = opts.threadId;
  }
  const filePath = join(repoPath, "requests", "pending", `${opts.requestId}.json`);
  writeFileSync(filePath, JSON.stringify(envelope, null, 2));
  execSync(`cd "${repoPath}" && git add -A && git commit -m "seed ${opts.requestId}" && git push`, {
    stdio: "pipe",
  });
}

describe("inbox enrichment: pact description and response fields in inbox entries", () => {
  let ctx: TestRepoContext;

  afterEach(() => {
    ctx?.cleanup();
  });

  // =========================================================================
  // Walking Skeleton
  // =========================================================================

  it("includes pact_description and response_fields in inbox entries for existing pacts", async () => {
    ctx = createTestRepos();

    await given("Cory sent a sanity-check request to Bob", () => {
      seedRequest(ctx.aliceRepo, {
        requestId: "req-20260222-100000-alice-e001",
        recipient: "bob",
        sender: "alice",
        senderName: "Alice",
        requestType: "sanity-check",
        question: "Does this memory leak match the session service pattern?",
      });
    });

    let inbox: any;

    await when("Bob checks his inbox", async () => {
      const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
      inbox = await bobServer.callTool("pact_do", { action: "inbox" });
    });

    await thenAssert("the inbox entry includes pact_description", () => {
      expect(inbox.requests).toHaveLength(1);
      expect(inbox.requests[0].pact_description).toBeDefined();
      expect(typeof inbox.requests[0].pact_description).toBe("string");
      expect(inbox.requests[0].pact_description.length).toBeGreaterThan(0);
    });

    await thenAssert("the inbox entry includes response_fields as an array of field names", () => {
      expect(inbox.requests[0].response_fields).toBeDefined();
      expect(Array.isArray(inbox.requests[0].response_fields)).toBe(true);
      expect(inbox.requests[0].response_fields).toEqual(
        expect.arrayContaining(["answer", "evidence", "recommendation"]),
      );
    });

    await thenAssert("existing inbox fields remain unchanged", () => {
      expect(inbox.requests[0].request_id).toBe("req-20260222-100000-alice-e001");
      expect(inbox.requests[0].request_type).toBe("sanity-check");
      expect(inbox.requests[0].sender).toBe("Alice");
      expect(inbox.requests[0].pact_path).toContain("pact-store/sanity-check.md");
    });
  });

  // =========================================================================
  // Happy Path -- Schema Preference
  // =========================================================================

  it("extracts response_fields from schema.json when available", async () => {
    ctx = createTestRepos();

    await given("the sanity-check pact has response fields defined in YAML frontmatter", () => {
      // pact-store/sanity-check.md (from createTestRepos) already has response_bundle
      // with fields: answer, evidence, concerns, recommendation
    });

    await given("Cory sent a sanity-check request to Bob", () => {
      seedRequest(ctx.aliceRepo, {
        requestId: "req-20260222-100000-alice-e002",
        recipient: "bob",
        sender: "alice",
        senderName: "Alice",
        requestType: "sanity-check",
      });
    });

    let inbox: any;

    await when("Bob checks his inbox", async () => {
      const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
      inbox = await bobServer.callTool("pact_do", { action: "inbox" });
    });

    await thenAssert("response_fields are extracted from schema.json response_bundle properties", () => {
      expect(inbox.requests[0].response_fields).toEqual(
        expect.arrayContaining(["answer", "evidence", "concerns", "recommendation"]),
      );
    });
  });

  it("falls back to PACT.md for response_fields when no schema.json exists", async () => {
    ctx = createTestRepos();

    await given("the ask pact has PACT.md but no schema.json", () => {
      mkdirSync(join(ctx.aliceRepo, "pacts", "ask"), { recursive: true });
      writeFileSync(join(ctx.aliceRepo, "pacts", "ask", "PACT.md"), ASK_PACT);
      execSync(
        `cd "${ctx.aliceRepo}" && git add -A && git commit -m "add ask pact" && git push`,
        { stdio: "pipe" },
      );
    });

    await given("Cory sent an ask request to Bob", () => {
      seedRequest(ctx.aliceRepo, {
        requestId: "req-20260222-110000-alice-e003",
        recipient: "bob",
        sender: "alice",
        senderName: "Alice",
        requestType: "ask",
        question: "What do you think about the migration plan?",
      });
    });

    let inbox: any;

    await when("Bob checks his inbox", async () => {
      const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
      inbox = await bobServer.callTool("pact_do", { action: "inbox" });
    });

    await thenAssert("the ask entry includes pact_description", () => {
      expect(inbox.requests[0].pact_description).toBeDefined();
      expect(inbox.requests[0].pact_description.length).toBeGreaterThan(0);
    });

    await thenAssert("response_fields are extracted from the PACT.md Response Structure table", () => {
      expect(inbox.requests[0].response_fields).toEqual(
        expect.arrayContaining(["answer", "reasoning", "caveats"]),
      );
    });
  });

  // =========================================================================
  // Happy Path -- Multiple Request Types
  // =========================================================================

  it("enriches multiple inbox entries of different pact types independently", async () => {
    ctx = createTestRepos();

    await given("the repo has sanity-check and ask pacts", () => {
      mkdirSync(join(ctx.aliceRepo, "pacts", "ask"), { recursive: true });
      writeFileSync(join(ctx.aliceRepo, "pacts", "ask", "PACT.md"), ASK_PACT);
      execSync(
        `cd "${ctx.aliceRepo}" && git add -A && git commit -m "add ask pact" && git push`,
        { stdio: "pipe" },
      );
    });

    await given("Bob has a sanity-check and an ask request pending", () => {
      seedRequest(ctx.aliceRepo, {
        requestId: "req-20260222-100000-alice-m001",
        recipient: "bob",
        sender: "alice",
        senderName: "Alice",
        requestType: "sanity-check",
        createdAt: "2026-02-22T10:00:00Z",
        question: "Sanity check question",
      });
      seedRequest(ctx.aliceRepo, {
        requestId: "req-20260222-110000-alice-m002",
        recipient: "bob",
        sender: "alice",
        senderName: "Alice",
        requestType: "ask",
        createdAt: "2026-02-22T11:00:00Z",
        question: "General ask question",
      });
    });

    let inbox: any;

    await when("Bob checks his inbox", async () => {
      const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
      inbox = await bobServer.callTool("pact_do", { action: "inbox" });
    });

    await thenAssert("each entry has enrichment from its own pact type", () => {
      expect(inbox.requests).toHaveLength(2);

      const sc = inbox.requests.find((r: any) => r.request_type === "sanity-check");
      expect(sc.pact_description).toBeDefined();
      expect(sc.response_fields).toEqual(
        expect.arrayContaining(["answer", "evidence", "recommendation"]),
      );

      const ask = inbox.requests.find((r: any) => r.request_type === "ask");
      expect(ask.pact_description).toBeDefined();
      expect(ask.response_fields).toEqual(
        expect.arrayContaining(["answer", "reasoning", "caveats"]),
      );
    });
  });

  it("caches pact metadata so duplicate request types do not re-read files", async () => {
    ctx = createTestRepos();

    await given("Bob has 3 sanity-check requests pending", () => {
      for (let i = 1; i <= 3; i++) {
        seedRequest(ctx.aliceRepo, {
          requestId: `req-20260222-${String(100000 + i)}-alice-c00${i}`,
          recipient: "bob",
          sender: "alice",
          senderName: "Alice",
          requestType: "sanity-check",
          createdAt: `2026-02-22T${10 + i}:00:00Z`,
          question: `Question ${i}`,
        });
      }
    });

    let inbox: any;

    await when("Bob checks his inbox", async () => {
      const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
      inbox = await bobServer.callTool("pact_do", { action: "inbox" });
    });

    await thenAssert("all 3 entries have identical enrichment (proving cache consistency)", () => {
      expect(inbox.requests).toHaveLength(3);
      const descriptions = inbox.requests.map((r: any) => r.pact_description);
      const fieldSets = inbox.requests.map((r: any) => JSON.stringify(r.response_fields));

      // All 3 should have the same enrichment from the same pact
      expect(new Set(descriptions).size).toBe(1);
      expect(new Set(fieldSets).size).toBe(1);
    });
  });

  // =========================================================================
  // Edge Cases / Error Paths
  // =========================================================================

  it("omits enrichment fields when pact file is missing without breaking inbox", async () => {
    ctx = createTestRepos();

    await given("a request with an unknown pact type exists for Bob", () => {
      seedRequest(ctx.aliceRepo, {
        requestId: "req-20260222-100000-alice-u001",
        recipient: "bob",
        sender: "alice",
        senderName: "Alice",
        requestType: "unknown-pact",
        question: "Request for nonexistent pact type",
      });
    });

    let inbox: any;

    await when("Bob checks his inbox", async () => {
      const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
      inbox = await bobServer.callTool("pact_do", { action: "inbox" });
    });

    await thenAssert("the inbox entry omits pact_description and response_fields", () => {
      expect(inbox.requests).toHaveLength(1);
      expect(inbox.requests[0].pact_description).toBeUndefined();
      expect(inbox.requests[0].response_fields).toBeUndefined();
    });

    await thenAssert("existing inbox fields are still present and correct", () => {
      expect(inbox.requests[0].request_id).toBe("req-20260222-100000-alice-u001");
      expect(inbox.requests[0].request_type).toBe("unknown-pact");
      expect(inbox.requests[0].sender).toBe("Alice");
      expect(inbox.requests[0].summary).toBeDefined();
    });
  });

  it("omits enrichment when PACT.md exists but is empty or unparseable", async () => {
    ctx = createTestRepos();

    await given("the repo has a pact with an empty PACT.md", () => {
      mkdirSync(join(ctx.aliceRepo, "pacts", "empty-pact"), { recursive: true });
      writeFileSync(join(ctx.aliceRepo, "pacts", "empty-pact", "PACT.md"), "");
      execSync(
        `cd "${ctx.aliceRepo}" && git add -A && git commit -m "empty pact" && git push`,
        { stdio: "pipe" },
      );
    });

    await given("a request for the empty pact exists for Bob", () => {
      seedRequest(ctx.aliceRepo, {
        requestId: "req-20260222-100000-alice-ep01",
        recipient: "bob",
        sender: "alice",
        senderName: "Alice",
        requestType: "empty-pact",
        question: "Empty pact test",
      });
    });

    let inbox: any;

    await when("Bob checks his inbox", async () => {
      const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
      inbox = await bobServer.callTool("pact_do", { action: "inbox" });
    });

    await thenAssert("enrichment fields are omitted but inbox does not error", () => {
      expect(inbox.requests).toHaveLength(1);
      // With an empty PACT.md, enrichment should gracefully degrade
      expect(inbox.requests[0].request_id).toBe("req-20260222-100000-alice-ep01");
    });
  });

  it("thread groups include enrichment from the pact metadata", async () => {
    ctx = createTestRepos();
    const threadId = "req-20260222-100000-alice-tg01";

    await given("Bob has 2 threaded sanity-check requests", () => {
      seedRequest(ctx.aliceRepo, {
        requestId: "req-20260222-100000-alice-tg01",
        recipient: "bob",
        sender: "alice",
        senderName: "Alice",
        requestType: "sanity-check",
        createdAt: "2026-02-22T10:00:00Z",
        question: "Round 1 question",
        threadId,
      });
      seedRequest(ctx.aliceRepo, {
        requestId: "req-20260222-110000-alice-tg02",
        recipient: "bob",
        sender: "alice",
        senderName: "Alice",
        requestType: "sanity-check",
        createdAt: "2026-02-22T11:00:00Z",
        question: "Round 2 question",
        threadId,
      });
    });

    let inbox: any;

    await when("Bob checks his inbox", async () => {
      const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
      inbox = await bobServer.callTool("pact_do", { action: "inbox" });
    });

    await thenAssert("the thread group includes pact_description and response_fields", () => {
      expect(inbox.requests).toHaveLength(1);
      const group = inbox.requests[0];
      expect(group.is_thread_group).toBe(true);
      expect(group.pact_description).toBeDefined();
      expect(group.response_fields).toBeDefined();
      expect(Array.isArray(group.response_fields)).toBe(true);
      expect(group.response_fields).toEqual(
        expect.arrayContaining(["answer", "evidence", "recommendation"]),
      );
    });
  });

  it("mixed inbox with enrichable and non-enrichable entries does not error", async () => {
    ctx = createTestRepos();

    await given("Bob has a sanity-check request and an unknown-pact request", () => {
      seedRequest(ctx.aliceRepo, {
        requestId: "req-20260222-100000-alice-mx01",
        recipient: "bob",
        sender: "alice",
        senderName: "Alice",
        requestType: "sanity-check",
        createdAt: "2026-02-22T10:00:00Z",
        question: "Known pact question",
      });
      seedRequest(ctx.aliceRepo, {
        requestId: "req-20260222-110000-alice-mx02",
        recipient: "bob",
        sender: "alice",
        senderName: "Alice",
        requestType: "nonexistent-type",
        createdAt: "2026-02-22T11:00:00Z",
        question: "Unknown pact question",
      });
    });

    let inbox: any;

    await when("Bob checks his inbox", async () => {
      const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
      inbox = await bobServer.callTool("pact_do", { action: "inbox" });
    });

    await thenAssert("both entries are returned", () => {
      expect(inbox.requests).toHaveLength(2);
    });

    await thenAssert("the sanity-check entry has enrichment", () => {
      const sc = inbox.requests.find((r: any) => r.request_type === "sanity-check");
      expect(sc.pact_description).toBeDefined();
      expect(sc.response_fields).toBeDefined();
    });

    await thenAssert("the unknown-pact entry omits enrichment gracefully", () => {
      const unknown = inbox.requests.find((r: any) => r.request_type === "nonexistent-type");
      expect(unknown.pact_description).toBeUndefined();
      expect(unknown.response_fields).toBeUndefined();
      // But other fields are present
      expect(unknown.request_id).toBe("req-20260222-110000-alice-mx02");
      expect(unknown.sender).toBe("Alice");
    });
  });
});

