/**
 * Acceptance Tests -- schema.json Convention and Validation Warnings
 *
 * Traces to: US-021
 *
 * Tests exercise the pact_request driving port (tool handler) against
 * real local git repos to verify schema.json validation behavior.
 * Scenarios verify:
 *   - pact_request warns when context_bundle is missing required fields defined in schema.json
 *   - pact_request does not warn when all required fields are present
 *   - pact_request skips validation entirely when no schema.json exists
 *   - Validation warnings are advisory (request still submits successfully)
 *   - schema.json allows additional properties beyond what is defined
 *   - Warning messages identify the missing field names
 *   - Malformed schema.json does not break request submission
 *
 * Error/edge scenarios: 4 of 9 total (44%)
 */

import { describe, it, expect, afterEach } from "vitest";
import {
  createTestRepos,
  listDir,
  readRepoJSON,
  type TestRepoContext,
} from "./helpers/setup-test-repos";
import { given, when, thenAssert } from "./helpers/gwt";
import { mkdirSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { execSync } from "node:child_process";
import { createPactServer } from "../../src/server.ts";

// ---------------------------------------------------------------------------
// Schema fixture
// ---------------------------------------------------------------------------

const SANITY_CHECK_SCHEMA = {
  $schema: "https://json-schema.org/draft/2020-12/schema",
  pact_name: "sanity-check",
  pact_version: "1.0.0",
  context_bundle: {
    type: "object",
    required: ["customer", "product", "issue_summary", "involved_files", "investigation_so_far", "question"],
    properties: {
      customer: { type: "string", description: "Customer name" },
      product: { type: "string", description: "Product name and version" },
      issue_summary: { type: "string", description: "Brief description of the issue" },
      involved_files: { type: "string", description: "Files examined" },
      investigation_so_far: { type: "string", description: "What you have found" },
      question: { type: "string", description: "Specific question for the reviewer" },
      zendesk_ticket: { type: "string", description: "Related Zendesk ticket ID" },
    },
    additionalProperties: true,
  },
  response_bundle: {
    type: "object",
    required: ["answer", "evidence", "recommendation"],
    properties: {
      answer: { type: "string", description: "YES / NO / PARTIALLY" },
      evidence: { type: "string", description: "What you compared" },
      concerns: { type: "string", description: "Risks or caveats" },
      recommendation: { type: "string", description: "Suggested next step" },
    },
    additionalProperties: true,
  },
};

/** Add schema.json to the sanity-check pact directory and push. */
function seedSchemaJson(repoPath: string, schema: Record<string, unknown> = SANITY_CHECK_SCHEMA): void {
  mkdirSync(join(repoPath, "pacts", "sanity-check"), { recursive: true });
  writeFileSync(
    join(repoPath, "pacts", "sanity-check", "schema.json"),
    JSON.stringify(schema, null, 2),
  );
  execSync(
    `cd "${repoPath}" && git add -A && git commit -m "add schema.json" && git push`,
    { stdio: "pipe" },
  );
}

describe("schema.json: typed pacts and validation warnings", () => {
  let ctx: TestRepoContext;

  afterEach(() => {
    ctx?.cleanup();
  });

  // =========================================================================
  // Walking Skeleton
  // =========================================================================

  it("warns on missing required fields and still submits the request successfully", async () => {
    ctx = createTestRepos();

    await given("the sanity-check pact has a schema.json with 6 required context fields", () => {
      seedSchemaJson(ctx.aliceRepo);
    });

    let result: any;

    await when("Alice submits a sanity-check request missing 'customer' and 'product'", async () => {
      const server = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      result = await server.callTool("pact_do", { action: "send",
        request_type: "sanity-check",
        recipient: "bob",
        context_bundle: {
          issue_summary: "Memory leak in auth refresh flow",
          involved_files: "src/auth/refresh.ts:L45-90",
          investigation_so_far: "Tokens held by closure",
          question: "Does this match the session service pattern?",
          // customer and product intentionally omitted
        },
      });
    });

    await thenAssert("the request is submitted successfully (not rejected)", () => {
      expect(result.request_id).toBeTruthy();
      expect(result.status).toBe("pending");
    });

    await thenAssert("the response includes validation_warnings mentioning missing fields", () => {
      expect(result.validation_warnings).toBeDefined();
      expect(Array.isArray(result.validation_warnings)).toBe(true);
      expect(result.validation_warnings.length).toBe(2);

      const warningText = result.validation_warnings.join(" ");
      expect(warningText).toMatch(/customer/i);
      expect(warningText).toMatch(/product/i);
    });

    await thenAssert("the request file exists on disk with the submitted bundle", () => {
      const pending = listDir(ctx.aliceRepo, "requests/pending");
      expect(pending).toHaveLength(1);

      const envelope = readRepoJSON<{ context_bundle: Record<string, unknown> }>(
        ctx.aliceRepo,
        `requests/pending/${result.request_id}.json`,
      );
      expect(envelope.context_bundle.issue_summary).toBe("Memory leak in auth refresh flow");
      expect(envelope.context_bundle.question).toBe("Does this match the session service pattern?");
    });
  });

  // =========================================================================
  // Happy Path
  // =========================================================================

  it("does not include validation_warnings when all required fields are present", async () => {
    ctx = createTestRepos();

    await given("the sanity-check pact has a schema.json", () => {
      seedSchemaJson(ctx.aliceRepo);
    });

    let result: any;

    await when("Alice submits a request with all 6 required context fields", async () => {
      const server = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      result = await server.callTool("pact_do", { action: "send",
        request_type: "sanity-check",
        recipient: "bob",
        context_bundle: {
          customer: "Acme Corp",
          product: "Platform v3.2",
          issue_summary: "Memory leak in auth refresh flow",
          involved_files: "src/auth/refresh.ts:L45-90",
          investigation_so_far: "Tokens held by closure, preventing GC",
          question: "Does this match the session service pattern?",
        },
      });
    });

    await thenAssert("the request is submitted successfully", () => {
      expect(result.request_id).toBeTruthy();
      expect(result.status).toBe("pending");
    });

    await thenAssert("the response includes an empty validation_warnings array", () => {
      expect(result.validation_warnings).toEqual([]);
    });
  });

  it("skips validation entirely when no schema.json exists for the pact", async () => {
    ctx = createTestRepos();

    await given("the sanity-check pact validates from YAML frontmatter (no schema.json needed)", () => {
      // createTestRepos already sets up sanity-check with just PACT.md
    });

    let result: any;

    await when("Alice submits a request with all required context fields", async () => {
      const server = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      result = await server.callTool("pact_do", { action: "send",
        request_type: "sanity-check",
        recipient: "bob",
        context_bundle: {
          customer: "Acme Corp",
          product: "Platform v3.2",
          issue_summary: "Memory leak",
          involved_files: "src/auth/refresh.ts",
          investigation_so_far: "Tokens held by closure",
          question: "Does this look right?",
        },
      });
    });

    await thenAssert("the request is submitted successfully with no warnings", () => {
      expect(result.request_id).toBeTruthy();
      expect(result.status).toBe("pending");
      expect(result.validation_warnings).toEqual([]);
    });
  });

  it("allows additional properties beyond what schema.json defines without warning", async () => {
    ctx = createTestRepos();

    await given("the sanity-check schema.json has additionalProperties: true", () => {
      seedSchemaJson(ctx.aliceRepo);
    });

    let result: any;

    await when("Alice submits a request with all required fields plus extra fields", async () => {
      const server = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      result = await server.callTool("pact_do", { action: "send",
        request_type: "sanity-check",
        recipient: "bob",
        context_bundle: {
          customer: "Acme Corp",
          product: "Platform v3.2",
          issue_summary: "Memory leak",
          involved_files: "src/auth/refresh.ts",
          investigation_so_far: "Tokens held by closure",
          question: "Pattern match?",
          internal_notes: "This is an extra field not in schema",
          priority: "high",
        },
      });
    });

    await thenAssert("the request is submitted with no warnings about extra fields", () => {
      expect(result.request_id).toBeTruthy();
      expect(result.validation_warnings).toEqual([]);
    });

    await thenAssert("the extra fields are preserved in the request envelope", () => {
      const envelope = readRepoJSON<{ context_bundle: Record<string, unknown> }>(
        ctx.aliceRepo,
        `requests/pending/${result.request_id}.json`,
      );
      expect(envelope.context_bundle.internal_notes).toBe("This is an extra field not in schema");
      expect(envelope.context_bundle.priority).toBe("high");
    });
  });

  it("warns only about the specific missing fields, not all required fields", async () => {
    ctx = createTestRepos();

    await given("the sanity-check schema.json requires 6 context fields", () => {
      seedSchemaJson(ctx.aliceRepo);
    });

    let result: any;

    await when("Alice submits a request missing only 'customer'", async () => {
      const server = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      result = await server.callTool("pact_do", { action: "send",
        request_type: "sanity-check",
        recipient: "bob",
        context_bundle: {
          // customer intentionally omitted
          product: "Platform v3.2",
          issue_summary: "Memory leak",
          involved_files: "src/auth/refresh.ts",
          investigation_so_far: "Tokens held by closure",
          question: "Pattern match?",
        },
      });
    });

    await thenAssert("exactly one warning is returned, mentioning 'customer'", () => {
      expect(result.validation_warnings).toHaveLength(1);
      expect(result.validation_warnings[0]).toMatch(/customer/i);
    });

    await thenAssert("the request is still submitted", () => {
      expect(result.request_id).toBeTruthy();
      const pending = listDir(ctx.aliceRepo, "requests/pending");
      expect(pending).toHaveLength(1);
    });
  });

  // =========================================================================
  // Error Paths / Edge Cases
  // =========================================================================

  it("handles malformed schema.json gracefully by skipping validation", async () => {
    ctx = createTestRepos();

    await given("the sanity-check pact has a malformed schema.json (not valid JSON Schema)", () => {
      mkdirSync(join(ctx.aliceRepo, "pacts", "sanity-check"), { recursive: true });
      writeFileSync(
        join(ctx.aliceRepo, "pacts", "sanity-check", "schema.json"),
        JSON.stringify({ not_a_real_schema: true }),
      );
      execSync(
        `cd "${ctx.aliceRepo}" && git add -A && git commit -m "bad schema" && git push`,
        { stdio: "pipe" },
      );
    });

    let result: any;

    await when("Alice submits a sanity-check request", async () => {
      const server = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      result = await server.callTool("pact_do", { action: "send",
        request_type: "sanity-check",
        recipient: "bob",
        context_bundle: {
          customer: "Acme Corp",
          product: "Platform v3.2",
          issue_summary: "Malformed schema test",
          involved_files: "src/test.ts",
          investigation_so_far: "Testing malformed schema handling",
          question: "Malformed schema test",
        },
      });
    });

    await thenAssert("the request submits successfully with no warnings (validation skipped)", () => {
      expect(result.request_id).toBeTruthy();
      expect(result.status).toBe("pending");
      expect(result.validation_warnings).toEqual([]);
    });
  });

  it("warns when context_bundle is completely empty but required fields exist", async () => {
    ctx = createTestRepos();

    await given("the sanity-check pact has a schema.json with 6 required fields", () => {
      seedSchemaJson(ctx.aliceRepo);
    });

    let result: any;

    await when("Alice submits a request with an empty context_bundle", async () => {
      const server = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      result = await server.callTool("pact_do", { action: "send",
        request_type: "sanity-check",
        recipient: "bob",
        context_bundle: {},
      });
    });

    await thenAssert("the request submits successfully (WARN not REJECT)", () => {
      expect(result.request_id).toBeTruthy();
      expect(result.status).toBe("pending");
    });

    await thenAssert("6 validation warnings are returned, one per missing required field", () => {
      expect(result.validation_warnings).toHaveLength(6);
      const warningText = result.validation_warnings.join(" ");
      expect(warningText).toMatch(/customer/i);
      expect(warningText).toMatch(/product/i);
      expect(warningText).toMatch(/issue_summary/i);
      expect(warningText).toMatch(/involved_files/i);
      expect(warningText).toMatch(/investigation_so_far/i);
      expect(warningText).toMatch(/question/i);
    });
  });

  it("does not validate when pact has schema.json but context_bundle.required is absent", async () => {
    ctx = createTestRepos();

    await given("the sanity-check pact has a schema.json without a required array", () => {
      const schemaNoRequired = {
        $schema: "https://json-schema.org/draft/2020-12/schema",
        pact_name: "sanity-check",
        pact_version: "1.0.0",
        context_bundle: {
          type: "object",
          properties: {
            question: { type: "string", description: "Question to ask" },
          },
          additionalProperties: true,
          // No required array
        },
      };
      mkdirSync(join(ctx.aliceRepo, "pacts", "sanity-check"), { recursive: true });
      writeFileSync(
        join(ctx.aliceRepo, "pacts", "sanity-check", "schema.json"),
        JSON.stringify(schemaNoRequired, null, 2),
      );
      execSync(
        `cd "${ctx.aliceRepo}" && git add -A && git commit -m "schema no required" && git push`,
        { stdio: "pipe" },
      );
    });

    let result: any;

    await when("Alice submits a request with minimal context", async () => {
      const server = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      result = await server.callTool("pact_do", { action: "send",
        request_type: "sanity-check",
        recipient: "bob",
        context_bundle: {
          customer: "Acme Corp",
          product: "Platform v3.2",
          issue_summary: "No required array test",
          involved_files: "src/test.ts",
          investigation_so_far: "Testing schema without required",
          question: "No required array test",
        },
      });
    });

    await thenAssert("the request submits with no validation warnings", () => {
      expect(result.request_id).toBeTruthy();
      expect(result.validation_warnings).toEqual([]);
    });
  });

  it("existing workflows work identically when schema.json is not present", async () => {
    ctx = createTestRepos();

    await given("the sanity-check pact has only PACT.md (no schema.json)", () => {
      // Default test setup -- no schema.json
    });

    let result: any;

    await when("Alice submits a request exactly as before Phase A", async () => {
      const server = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      result = await server.callTool("pact_do", { action: "send",
        request_type: "sanity-check",
        recipient: "bob",
        context_bundle: {
          customer: "Acme Corp",
          product: "Platform v3.2",
          issue_summary: "Memory leak in auth refresh flow",
          involved_files: "src/auth/refresh.ts:L45-90",
          investigation_so_far: "Tokens held by closure, preventing GC",
          question: "Does this match the session service pattern?",
        },
      });
    });

    await thenAssert("the request is submitted identically to pre-Phase-A behavior", () => {
      expect(result.request_id).toBeTruthy();
      expect(result.status).toBe("pending");
      expect(result.validation_warnings).toEqual([]);
    });

    await thenAssert("the request envelope has the standard structure", () => {
      const envelope = readRepoJSON<Record<string, unknown>>(
        ctx.aliceRepo,
        `requests/pending/${result.request_id}.json`,
      );
      expect(envelope.request_type).toBe("sanity-check");
      expect(envelope.status).toBe("pending");
      expect((envelope.sender as any).user_id).toBe("alice");
      expect((envelope.recipient as any).user_id).toBe("bob");
    });
  });
});

tests/acceptance/y30-group-error-paths.t.source:
/**
 * Milestone 4: Group Addressing Error Paths and Backward Compatibility
 *
 * pact-y30 epic — validates error handling and migration:
 *   - Unknown recipient in recipients[] array
 *   - Non-recipient trying to respond
 *   - Empty recipients array
 *   - Old single-response file format still readable
 *   - Old recipient field coerced to recipients[] on read
 *
 * Exercises driving ports: pact_do(send, respond, check_status, view_thread)
 * Integration contracts: IC1 (group send validation), IC3 (response storage),
 *   IC6 (backward compat)
 *
 * Error scenarios: 6 of 10 total (60%)
 *
 * @skip — Enable when recipients[] schema migration is implemented.
 */

import { describe, it, expect, afterEach } from "vitest";
import {
  createTestRepos,
  seedPendingRequest,
  listDir,
  readRepoJSON,
  fileExists,
  gitPull,
  type TestRepoContext,
} from "./helpers/setup-test-repos";
import { given, when, thenAssert } from "./helpers/gwt";
import { writeFileSync, mkdirSync } from "node:fs";
import { join } from "node:path";
import { execSync } from "node:child_process";
import { createPactServer } from "../../src/server.ts";

// ---------------------------------------------------------------------------
// Multi-member team setup
// ---------------------------------------------------------------------------

function createGroupTestRepos(): TestRepoContext & { carolRepo: string } {
  const ctx = createTestRepos();

  const config = JSON.parse(
    require("node:fs").readFileSync(join(ctx.aliceRepo, "config.json"), "utf-8"),
  );
  config.members.push({ user_id: "carol", display_name: "Carol" });
  writeFileSync(join(ctx.aliceRepo, "config.json"), JSON.stringify(config, null, 2));
  execSync(
    `cd "${ctx.aliceRepo}" && git add config.json && git commit -m "add carol" && git push`,
    { stdio: "pipe" },
  );

  const carolRepo = join(ctx.basePath, "carol");
  execSync(`git clone "${ctx.remotePath}" "${carolRepo}"`, { stdio: "pipe" });
  execSync(
    `cd "${carolRepo}" && git config user.email "carol@test.local" && git config user.name "Carol"`,
    { stdio: "pipe" },
  );

  gitPull(ctx.bobRepo);

  const origCleanup = ctx.cleanup;
  return {
    ...ctx,
    carolRepo,
    cleanup: () => origCleanup(),
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("Group addressing error paths and backward compat (pact-y30)", () => {
  let ctx: ReturnType<typeof createGroupTestRepos>;

  afterEach(() => {
    ctx?.cleanup();
  });

  // =========================================================================
  // Error: Invalid recipients
  // =========================================================================

  it("accepts send to unknown recipients without validation", async () => {
    ctx = createGroupTestRepos();

    const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });

    let requestId: string;

    await when("Alice sends to a mix of known and unknown recipients", async () => {
      const result = (await aliceServer.callTool("pact_do", {
        action: "send",
        request_type: "sanity-check",
        recipients: ["bob", "nonexistent-user"],
        context_bundle: { question: "Will this fail?" },
      })) as { request_id: string };
      requestId = result.request_id;
    });

    await thenAssert("the request was created successfully", () => {
      expect(requestId).toBeTruthy();
      const pending = listDir(ctx.aliceRepo, "requests/pending");
      expect(pending).toHaveLength(1);
    });
  });

  it("rejects send with empty recipients array", async () => {
    ctx = createGroupTestRepos();

    const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });

    let error: any;

    await when("Alice sends a request with empty recipients array", async () => {
      try {
        await aliceServer.callTool("pact_do", {
          action: "send",
          request_type: "sanity-check",
          recipients: [],
          context_bundle: { question: "Who receives this?" },
        });
      } catch (e) {
        error = e;
      }
    });

    await thenAssert("send fails with validation error", () => {
      expect(error).toBeDefined();
    });
  });

  it("rejects send when sender is in recipients array", async () => {
    ctx = createGroupTestRepos();

    const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });

    let error: any;

    await when("Alice includes herself in the recipients array", async () => {
      try {
        await aliceServer.callTool("pact_do", {
          action: "send",
          request_type: "sanity-check",
          recipients: ["alice", "bob"],
          context_bundle: { question: "Can I send to myself?" },
        });
      } catch (e) {
        error = e;
      }
    });

    await thenAssert("send fails because sender cannot be a recipient", () => {
      expect(error).toBeDefined();
    });
  });

  // =========================================================================
  // Error: Non-recipient responding
  // =========================================================================

  it("rejects response from user not in recipients array", async () => {
    ctx = createGroupTestRepos();

    const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
    const carolServer = createPactServer({ repoPath: ctx.carolRepo, userId: "carol" });

    let requestId: string;
    let error: any;

    await given("Alice sends a request to Bob only", async () => {
      const result = (await aliceServer.callTool("pact_do", {
        action: "send",
        request_type: "sanity-check",
        recipients: ["bob"],
        context_bundle: { question: "Bob only" },
      })) as { request_id: string };
      requestId = result.request_id;
    });

    await when("Carol (not a recipient) tries to respond", async () => {
      gitPull(ctx.carolRepo);
      try {
        await carolServer.callTool("pact_do", {
          action: "respond",
          request_id: requestId,
          response_bundle: { answer: "I was not asked" },
        });
      } catch (e) {
        error = e;
      }
    });

    await thenAssert("response is rejected because Carol is not a recipient", () => {
      expect(error).toBeDefined();
      expect(String(error)).toMatch(/not.*recipient|not.*authorized/i);
    });
  });

  // =========================================================================
  // Error: Duplicate response
  // =========================================================================

  it("rejects duplicate response from same recipient", async () => {
    ctx = createGroupTestRepos();

    const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
    const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });

    let requestId: string;
    let error: any;

    await given("Alice sends a group request and Bob already responded", async () => {
      const result = (await aliceServer.callTool("pact_do", {
        action: "send",
        request_type: "sanity-check",
        recipients: ["bob", "carol"],
        context_bundle: { question: "Double respond test" },
      })) as { request_id: string };
      requestId = result.request_id;

      gitPull(ctx.bobRepo);
      await bobServer.callTool("pact_do", {
        action: "respond",
        request_id: requestId,
        response_bundle: { answer: "First response" },
      });
    });

    await when("Bob tries to respond a second time", async () => {
      try {
        await bobServer.callTool("pact_do", {
          action: "respond",
          request_id: requestId,
          response_bundle: { answer: "Second response" },
        });
      } catch (e) {
        error = e;
      }
    });

    await thenAssert("duplicate response is rejected", () => {
      expect(error).toBeDefined();
    });
  });

  // =========================================================================
  // Backward compatibility: old single-recipient format
  // =========================================================================

  it("inbox reads old-format requests with single recipient field", async () => {
    ctx = createGroupTestRepos();

    await given("a request exists with old-format single recipient field", () => {
      // Seed a request with old-format: `recipient` instead of `recipients`
      seedPendingRequest(ctx.aliceRepo, "req-20260223-100000-alice-old1", "bob", "alice");
    });

    await thenAssert("Bob can see the old-format request in inbox", async () => {
      gitPull(ctx.bobRepo);
      const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
      const inbox = (await bobServer.callTool("pact_do", { action: "inbox" })) as {
        requests: any[];
      };
      expect(inbox.requests).toHaveLength(1);
      expect(inbox.requests[0].request_id).toBe("req-20260223-100000-alice-old1");
    });
  });

  it("status reads old-format single response file alongside per-respondent directory", async () => {
    ctx = createGroupTestRepos();

    await given("a completed request exists with old-format single response file", () => {
      // Seed old-format: response as responses/{id}.json (file, not directory)
      seedPendingRequest(ctx.aliceRepo, "req-20260223-100000-alice-old2", "bob", "alice");

      gitPull(ctx.bobRepo);
      const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
      // Respond using current system (creates old-format response file)
      return bobServer.callTool("pact_do", {
        action: "respond",
        request_id: "req-20260223-100000-alice-old2",
        response_bundle: { answer: "Old format response" },
      });
    });

    await thenAssert("Alice can check status and see the old-format response", async () => {
      gitPull(ctx.aliceRepo);
      const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
      const status = (await aliceServer.callTool("pact_do", {
        action: "check_status",
        request_id: "req-20260223-100000-alice-old2",
      })) as any;
      expect(status.status).toBe("completed");
      expect(status.response.response_bundle.answer).toBe("Old format response");
    });
  });

  // =========================================================================
  // Thread with per-respondent responses
  // =========================================================================

  it("view_thread shows all per-respondent responses for a group request", async () => {
    ctx = createGroupTestRepos();

    const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
    const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
    const carolServer = createPactServer({ repoPath: ctx.carolRepo, userId: "carol" });

    let requestId: string;

    await given("Alice sends a group request and both recipients respond", async () => {
      const result = (await aliceServer.callTool("pact_do", {
        action: "send",
        request_type: "sanity-check",
        recipients: ["bob", "carol"],
        context_bundle: { question: "Thread test" },
      })) as { request_id: string };
      requestId = result.request_id;

      gitPull(ctx.bobRepo);
      await bobServer.callTool("pact_do", {
        action: "respond",
        request_id: requestId,
        response_bundle: { answer: "Bob's thread entry" },
      });

      gitPull(ctx.carolRepo);
      await carolServer.callTool("pact_do", {
        action: "respond",
        request_id: requestId,
        response_bundle: { answer: "Carol's thread entry" },
      });
    });

    await thenAssert("thread shows both responses", async () => {
      gitPull(ctx.aliceRepo);
      const thread = (await aliceServer.callTool("pact_do", {
        action: "view_thread",
        request_id: requestId,
      })) as any;
      const responses = Array.isArray(thread.responses) ? thread.responses : [thread.response];
      expect(responses.length).toBeGreaterThanOrEqual(2);
      const responderIds = responses.map((r: any) => r.responder.user_id);
      expect(responderIds).toContain("bob");
      expect(responderIds).toContain("carol");
    });
  });
});

tests/acceptance/y30-group-walking-skele.source:
/**
 * Walking Skeleton: Group Request Round-Trip
 *
 * pact-y30 epic — validates the core group addressing lifecycle:
 *   1. Alice sends a request to multiple recipients (bob, carol)
 *   2. Both recipients see the request in their inbox
 *   3. Bob responds — per-respondent response file created
 *   4. Alice checks status and sees Bob's response
 *   5. Carol responds — second per-respondent response file created
 *   6. Alice sees both responses
 *
 * Exercises driving ports: pact_do(send, inbox, respond, check_status)
 * Integration contracts: IC1 (group send), IC2 (inbox filtering),
 *   IC3 (per-respondent storage)
 *
 * @skip — Enable when recipients[] schema and per-respondent storage are implemented.
 */

import { describe, it, expect, afterEach } from "vitest";
import {
  createTestRepos,
  listDir,
  readRepoJSON,
  fileExists,
  gitPull,
  type TestRepoContext,
} from "./helpers/setup-test-repos";
import { given, when, thenAssert } from "./helpers/gwt";
import { createPactServer } from "../../src/server.ts";
import { mkdirSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { execSync } from "node:child_process";

// ---------------------------------------------------------------------------
// Multi-member team setup (extends alice+bob with carol)
// ---------------------------------------------------------------------------

function createGroupTestRepos(): TestRepoContext & { carolRepo: string } {
  const ctx = createTestRepos();

  // Add carol to team config in alice's repo
  const config = JSON.parse(
    require("node:fs").readFileSync(join(ctx.aliceRepo, "config.json"), "utf-8"),
  );
  config.members.push({ user_id: "carol", display_name: "Carol" });
  writeFileSync(join(ctx.aliceRepo, "config.json"), JSON.stringify(config, null, 2));
  execSync(
    `cd "${ctx.aliceRepo}" && git add config.json && git commit -m "add carol to team" && git push`,
    { stdio: "pipe" },
  );

  // Clone for Carol
  const carolRepo = join(ctx.basePath, "carol");
  execSync(`git clone "${ctx.remotePath}" "${carolRepo}"`, { stdio: "pipe" });
  execSync(
    `cd "${carolRepo}" && git config user.email "carol@test.local" && git config user.name "Carol"`,
    { stdio: "pipe" },
  );

  // Update Bob's clone
  gitPull(ctx.bobRepo);

  const origCleanup = ctx.cleanup;
  return {
    ...ctx,
    carolRepo,
    cleanup: () => origCleanup(),
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe("Walking Skeleton: group request round-trip (pact-y30)", () => {
  let ctx: ReturnType<typeof createGroupTestRepos>;

  afterEach(() => {
    ctx?.cleanup();
  });

  // =========================================================================
  // WALKING SKELETON 1: Full group request-respond lifecycle
  // =========================================================================

  it("Alice sends a request to Bob and Carol, both respond, Alice sees all responses", async () => {
    ctx = createGroupTestRepos();

    const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
    const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });
    const carolServer = createPactServer({ repoPath: ctx.carolRepo, userId: "carol" });

    let requestId: string;

    // --- Given: team has 3 members and a pact installed ---

    await given("team has alice, bob, and carol with a sanity-check pact", async () => {
      expect(fileExists(ctx.aliceRepo, "config.json")).toBe(true);
      expect(fileExists(ctx.aliceRepo, "pact-store/sanity-check.md")).toBe(true);
    });

    // --- When: Alice sends a group request ---

    await when("Alice sends a sanity-check request to Bob and Carol", async () => {
      const result = (await aliceServer.callTool("pact_do", {
        action: "send",
        request_type: "sanity-check",
        recipients: ["bob", "carol"],
        context_bundle: {
          customer: "Acme Corp",
          product: "Platform v3.2",
          issue_summary: "Token cache not clearing on logout",
          involved_files: "src/auth/cache.ts:L20-50",
          investigation_so_far: "Cache entries persist after session end",
          question: "Is this the same pattern we saw in the session service?",
        },
      })) as { request_id: string };
      requestId = result.request_id;
      expect(requestId).toBeTruthy();
    });

    // --- Then: request envelope has recipients[] ---

    await thenAssert("request envelope lists both recipients", async () => {
      const pendingFiles = listDir(ctx.aliceRepo, "requests/pending");
      expect(pendingFiles).toHaveLength(1);
      const envelope = readRepoJSON<any>(ctx.aliceRepo, `requests/pending/${pendingFiles[0]}`);
      expect(envelope.recipients).toHaveLength(2);
      const recipientIds = envelope.recipients.map((r: any) => r.user_id);
      expect(recipientIds).toContain("bob");
      expect(recipientIds).toContain("carol");
    });

    // --- Then: both recipients see the request ---

    await thenAssert("Bob sees the group request in his inbox", async () => {
      gitPull(ctx.bobRepo);
      const inbox = (await bobServer.callTool("pact_do", { action: "inbox" })) as {
        requests: any[];
      };
      expect(inbox.requests).toHaveLength(1);
      expect(inbox.requests[0].request_id).toBe(requestId);
    });

    await thenAssert("Carol sees the group request in her inbox", async () => {
      gitPull(ctx.carolRepo);
      const inbox = (await carolServer.callTool("pact_do", { action: "inbox" })) as {
        requests: any[];
      };
      expect(inbox.requests).toHaveLength(1);
      expect(inbox.requests[0].request_id).toBe(requestId);
    });

    // --- When: Bob responds ---

    await when("Bob responds with his findings", async () => {
      const response = (await bobServer.callTool("pact_do", {
        action: "respond",
        request_id: requestId,
        response_bundle: {
          answer: "YES — same pattern as ZD-4102",
          evidence: "Compared cache.ts:L20-50 with cleanup.ts:L30-60",
          concerns: "The token-cache module may have the same issue",
          recommendation: "Apply finally-block cleanup",
        },
      })) as { status: string };
      expect(response.status).toBe("completed");
    });

    // --- Then: per-respondent response file exists ---

    await thenAssert("Bob's response is stored as a per-respondent file", async () => {
      gitPull(ctx.aliceRepo);
      expect(fileExists(ctx.aliceRepo, `responses/${requestId}/bob.json`)).toBe(true);
      const bobResponse = readRepoJSON<any>(ctx.aliceRepo, `responses/${requestId}/bob.json`);
      expect(bobResponse.responder.user_id).toBe("bob");
      expect(bobResponse.response_bundle.answer).toContain("ZD-4102");
    });

    // --- When: Carol responds ---

    await when("Carol responds with her findings", async () => {
      gitPull(ctx.carolRepo);
      const response = (await carolServer.callTool("pact_do", {
        action: "respond",
        request_id: requestId,
        response_bundle: {
          answer: "PARTIALLY — similar but not identical",
          evidence: "The lifecycle differs from the session service",
          concerns: "Need to check if the cache has a TTL",
          recommendation: "Add TTL to cache entries before applying cleanup",
        },
      })) as { status: string };
      expect(response.status).toBe("completed");
    });

    // --- Then: both responses visible ---

    await thenAssert("Alice sees both per-respondent responses", async () => {
      gitPull(ctx.aliceRepo);
      expect(fileExists(ctx.aliceRepo, `responses/${requestId}/bob.json`)).toBe(true);
      expect(fileExists(ctx.aliceRepo, `responses/${requestId}/carol.json`)).toBe(true);
    });

    // --- When: Alice checks status ---

    await when("Alice checks status and sees both responses", async () => {
      const status = (await aliceServer.callTool("pact_do", {
        action: "check_status",
        request_id: requestId,
      })) as any;
      expect(status.status).toBe("completed");
      // Should have responses from both bob and carol
      const responses = Array.isArray(status.responses) ? status.responses : [status.response];
      const responderIds = responses.map((r: any) => r.responder.user_id);
      expect(responderIds).toContain("bob");
      expect(responderIds).toContain("carol");
    });
  });

  // =========================================================================
  // WALKING SKELETON 2: Group inbox enrichment
  // =========================================================================

  it("inbox entries for group requests include recipient count and group reference", async () => {
    ctx = createGroupTestRepos();

    const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
    const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });

    let requestId: string;

    await given("Alice sends a group request with a group reference", async () => {
      const result = (await aliceServer.callTool("pact_do", {
        action: "send",
        request_type: "sanity-check",
        recipients: ["bob", "carol"],
        group_ref: "@backend-team",
        context_bundle: {
          customer: "Acme Corp",
          question: "Does this look right?",
        },
      })) as { request_id: string };
      requestId = result.request_id;
    });

    await thenAssert("Bob's inbox shows recipient count and group reference", async () => {
      gitPull(ctx.bobRepo);
      const inbox = (await bobServer.callTool("pact_do", { action: "inbox" })) as {
        requests: any[];
      };
      const entry = inbox.requests.find((r: any) => r.request_id === requestId);
      expect(entry).toBeDefined();
      expect(entry.recipients_count).toBe(2);
      expect(entry.group_ref).toBe("@backend-team");
    });
  });

  // =========================================================================
  // WALKING SKELETON 3: Single recipient still works (backward compat)
  // =========================================================================

  it("single-recipient request works with recipients[] array of one", async () => {
    ctx = createGroupTestRepos();

    const aliceServer = createPactServer({ repoPath: ctx.aliceRepo, userId: "alice" });
    const bobServer = createPactServer({ repoPath: ctx.bobRepo, userId: "bob" });

    let requestId: string;

    await when("Alice sends a request to only Bob using recipients array", async () => {
      const result = (await aliceServer.callTool("pact_do", {
        action: "send",
        request_type: "sanity-check",
        recipients: ["bob"],
        context_bundle: {
          customer: "Acme Corp",
          question: "Quick check on this?",
        },
      })) as { request_id: string };
      requestId = result.request_id;
    });

    await thenAssert("Bob sees the request and can respond normally", async () => {
      gitPull(ctx.bobRepo);
      const inbox = (await bobServer.callTool("pact_do", { action: "inbox" })) as {
        requests: any[];
      };
      expect(inbox.requests).toHaveLength(1);

      const response = (await bobServer.callTool("pact_do", {
        action: "respond",
        request_id: requestId,
        response_bundle: { answer: "Looks good" },
      })) as { status: string };
      expect(response.status).toBe("completed");
    });

    await thenAssert("response stored in per-respondent directory format", async () => {
      gitPull(ctx.aliceRepo);
      expect(fileExists(ctx.aliceRepo, `responses/${requestId}/bob.json`)).toBe(true);
    });
  });
});

